// Evaluate completeness of the advisor profile and prepare the welcome draft prompt.
// Called once per pending advisor row that arrived from Read pending advisors.
const a = $json || {};
const nowIso = new Date().toISOString();

// Required fields (hard gate)
const required = {
  photo_url:    (typeof a.photo_url === 'string' && a.photo_url.trim().length > 0),
  bio:          (typeof a.bio === 'string' && a.bio.trim().length >= 50),
  specialties:  (Array.isArray(a.specialties) && a.specialties.length > 0),
  email:        (typeof a.email === 'string' && /@/.test(a.email)),
  location:     (typeof a.location_display === 'string' && a.location_display.trim().length > 0),
  years_exp:    (typeof a.years_experience === 'number' && a.years_experience >= 0),
};
// Credentialed-profession gate: AFSL for financial advisors, registration_number for others that need it
const needsAfsl = ['financial_advisor','wealth_manager','stockbroker','accountant'].includes(a.type);
if (needsAfsl) {
  required.afsl_or_reg = (typeof a.afsl_number === 'string' && a.afsl_number.trim().length > 0)
    || (typeof a.registration_number === 'string' && a.registration_number.trim().length > 0);
}

const missing_fields = Object.entries(required).filter(([, ok]) => !ok).map(([k]) => k);
const is_complete = missing_fields.length === 0;

let welcome_prompt_system = null;
let welcome_prompt_user = null;
if (is_complete) {
  welcome_prompt_system = [
    "You are the Advisor Onboarding agent for invest.com.au. You draft the first welcome email to a newly-verified advisor who has passed the profile quality gate.",
    "Voice: warm, professional, concise. Match the brand voice from COMPANY.md (Australian English, general-advice disclaimer not required in onboarding).",
    "Do NOT make any claim about lead volume, pricing, or returns that the advisor hasn't already been shown in the product flow.",
    "Do NOT use forbidden phrases ('we recommend', 'best for you', 'you should'). Avoid exclamation marks.",
    "",
    "Return a JSON block (```json ... ```) with keys: subject (<=80 chars), body_plain (<=800 chars, plain text), body_html (optional, same content with safe <p>/<strong>/<a> tags), next_steps (array of 3 short strings).",
    "Follow the JSON block with nothing else."
  ].join('\n');
  welcome_prompt_user = [
    `New advisor ready for onboarding:`,
    '```json',
    JSON.stringify({
      name: a.name,
      firm_name: a.firm_name,
      type: a.type,
      specialties: a.specialties,
      location: a.location_display,
      years_experience: a.years_experience,
      booking_enabled: a.booking_enabled,
    }, null, 2),
    '```',
    '',
    'Task: draft the welcome email for this advisor. Reference one of their specialties if present. Close with three clear next steps (fill portal, confirm availability, accept first lead).',
  ].join('\n');
}

return {
  json: {
    advisor_id: a.id,
    advisor_slug: a.slug,
    advisor_name: a.name,
    advisor_email: a.email,
    advisor_type: a.type,
    is_complete,
    missing_fields,
    welcome_prompt_system,
    welcome_prompt_user,
    run_at: nowIso,
  }
};

const resp = $json || {};
const evalOut = $('Evaluate profile').item.json;

const textBlocks = Array.isArray(resp.content) ? resp.content.filter(c => c && c.type === 'text').map(c => c.text || '') : [];
const combined = textBlocks.join('\n');

let parsed = null;
const fence = combined.match(/```json\s*([\s\S]*?)```/i);
if (fence) { try { parsed = JSON.parse(fence[1].trim()); } catch (e) { parsed = null; } }
if (!parsed) {
  const brace = combined.match(/\{[\s\S]*\}/);
  if (brace) { try { parsed = JSON.parse(brace[0]); } catch (e) { parsed = null; } }
}

const subject = (parsed && typeof parsed.subject === 'string') ? parsed.subject.slice(0, 120) : `Welcome to invest.com.au, ${evalOut.advisor_name}`;
const body_plain = (parsed && typeof parsed.body_plain === 'string') ? parsed.body_plain.slice(0, 4000) : combined.slice(0, 4000);
const body_html = (parsed && typeof parsed.body_html === 'string') ? parsed.body_html.slice(0, 6000) : null;
const next_steps = (parsed && Array.isArray(parsed.next_steps)) ? parsed.next_steps.slice(0, 5).map(s => String(s).slice(0, 240)) : [];

return {
  json: {
    advisor_id: evalOut.advisor_id,
    advisor_slug: evalOut.advisor_slug,
    advisor_name: evalOut.advisor_name,
    advisor_email: evalOut.advisor_email,
    advisor_type: evalOut.advisor_type,
    run_at: evalOut.run_at,
    email_draft: {
      subject,
      body_plain,
      body_html,
      next_steps,
    },
    claude_raw: combined.slice(0, 4000),
    claude_usage: resp.usage,
    claude_model: resp.model || 'claude-opus-4-7',
    claude_stop_reason: resp.stop_reason,
  }
};
